import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { fetchAdminB2bOrders, approveB2bOrder, updateB2bOrderStatus, setB2bTracking } from "../../features/b2b/adminB2bSlice";
import { getSocket } from "../../socket";
import { toast } from "react-toastify";
import {
  Package, Clock, CheckCircle2, Truck, XCircle, Search,
  Filter, ChevronDown, ShieldCheck, ArrowLeft, Loader2,
  Eye, MoreHorizontal, AlertTriangle
} from "lucide-react";
import { Link } from "react-router-dom";

const statusConfig = {
  PENDING_APPROVAL: { label: "Pending Approval", color: "bg-amber-50 text-amber-700 border-amber-200", icon: Clock },
  APPROVED: { label: "Approved", color: "bg-indigo-50 text-indigo-700 border-indigo-200", icon: CheckCircle2 },
  PROCESSING: { label: "Processing", color: "bg-violet-50 text-violet-700 border-violet-200", icon: Package },
  SHIPPED: { label: "Shipped", color: "bg-cyan-50 text-cyan-700 border-cyan-200", icon: Truck },
  PARTIALLY_SHIPPED: { label: "Partial Ship", color: "bg-sky-50 text-sky-700 border-sky-200", icon: Truck },
  DELIVERED: { label: "Delivered", color: "bg-emerald-50 text-emerald-700 border-emerald-200", icon: CheckCircle2 },
  CANCELLED: { label: "Cancelled", color: "bg-rose-50 text-rose-700 border-rose-200", icon: XCircle },
};

const AdminB2bOrders = () => {
  const dispatch = useDispatch();
  const { orders, ordersMeta, isLoading } = useSelector((s) => s.adminB2b);

  const [statusFilter, setStatusFilter] = useState("");
  const [searchTerm, setSearchTerm] = useState("");
  const [page, setPage] = useState(1);
  const [expandedId, setExpandedId] = useState(null);
  const [trackingInput, setTrackingInput] = useState("");
  const [statusUpdateId, setStatusUpdateId] = useState(null);
  const [newStatus, setNewStatus] = useState("");

  const fetchOrders = () => {
    const params = { page, limit: 20 };
    if (statusFilter) params.procurementStatus = statusFilter;
    if (searchTerm) params.search = searchTerm;
    dispatch(fetchAdminB2bOrders(params));
  };

  useEffect(() => { fetchOrders(); }, [statusFilter, page]);

  useEffect(() => {
    const socket = getSocket();
    if (!socket) return;
    const refresh = () => fetchOrders();
    socket.on("b2b:order:created", refresh);
    socket.on("b2b:order:updated", refresh);
    socket.on("b2b:payment:verified", refresh);
    return () => {
      socket.off("b2b:order:created", refresh);
      socket.off("b2b:order:updated", refresh);
      socket.off("b2b:payment:verified", refresh);
    };
  }, [statusFilter, page]);

  const handleApprove = async (id) => {
    try {
      await dispatch(approveB2bOrder(id)).unwrap();
      toast.success("Order approved!");
      fetchOrders();
    } catch (err) { toast.error(err || "Approve failed"); }
  };

  const handleStatusUpdate = async (id) => {
    if (!newStatus) return;
    try {
      await dispatch(updateB2bOrderStatus({ id, status: newStatus })).unwrap();
      toast.success(`Status updated to ${newStatus}`);
      setStatusUpdateId(null);
      setNewStatus("");
      fetchOrders();
    } catch (err) { toast.error(err || "Status update failed"); }
  };

  const handleSetTracking = async (id) => {
    if (!trackingInput) return;
    try {
      await dispatch(setB2bTracking({ id, trackingNumber: trackingInput })).unwrap();
      toast.success("Tracking number set!");
      setTrackingInput("");
      fetchOrders();
    } catch (err) { toast.error(err || "Tracking update failed"); }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    setPage(1);
    fetchOrders();
  };

  return (
    <div className="min-h-screen bg-[#f8fafc]">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
          <div>
            <Link to="/admin" className="flex items-center gap-1.5 text-sm font-bold text-slate-400 hover:text-indigo-600 mb-2">
              <ArrowLeft size={16} /> Admin Dashboard
            </Link>
            <h1 className="text-2xl font-black text-slate-900">B2B Procurement Orders</h1>
            <p className="text-sm text-slate-500 font-medium mt-1">
              Manage wholesale orders, approve procurement requests, track shipments
            </p>
          </div>
        </div>

        {/* Filters */}
        <div className="bg-white rounded-3xl border border-slate-100 p-5 mb-6 shadow-sm flex flex-col sm:flex-row gap-4">
          <form onSubmit={handleSearch} className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input
              type="text"
              placeholder="Search by institution, TX ref, PO number..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10 pr-4 h-10 w-full bg-slate-50 border border-slate-200 rounded-xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500/20"
            />
          </form>
          <select
            value={statusFilter}
            onChange={(e) => { setStatusFilter(e.target.value); setPage(1); }}
            className="h-10 px-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-600"
          >
            <option value="">All Statuses</option>
            {Object.entries(statusConfig).map(([key, { label }]) => (
              <option key={key} value={key}>{label}</option>
            ))}
          </select>
        </div>

        {/* Orders Table */}
        {isLoading ? (
          <div className="flex items-center justify-center py-24">
            <div className="w-10 h-10 rounded-full border-2 border-indigo-600 border-t-transparent animate-spin" />
          </div>
        ) : orders?.length > 0 ? (
          <div className="flex flex-col gap-4">
            {orders.map((order) => {
              const cfg = statusConfig[order.procurementStatus] || statusConfig.PENDING_APPROVAL;
              const StatusIcon = cfg.icon;
              const institution = order.user?.institutionName || `${order.firstName} ${order.lastName}`;
              const total = parseFloat(order.totalPrice || 0);
              const date = order.createdAt ? new Date(order.createdAt).toLocaleDateString("en-US", {
                year: "numeric", month: "short", day: "numeric",
              }) : "—";
              const isExpanded = expandedId === order.id;

              return (
                <div key={order.id} className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
                  {/* Row */}
                  <div
                    className="p-5 flex flex-col sm:flex-row sm:items-center gap-4 cursor-pointer hover:bg-slate-50/50 transition-colors"
                    onClick={() => setExpandedId(isExpanded ? null : order.id)}
                  >
                    <div className="flex items-center gap-3 sm:w-48 flex-shrink-0">
                      <div className={`w-9 h-9 rounded-xl flex items-center justify-center border ${cfg.color}`}>
                        <StatusIcon size={16} />
                      </div>
                      <div>
                        <span className={`text-[9px] font-black uppercase tracking-widest px-1.5 py-0.5 rounded border ${cfg.color}`}>
                          {cfg.label}
                        </span>
                        <p className="text-[10px] text-slate-400 font-medium mt-0.5">{date}</p>
                      </div>
                    </div>

                    <div className="flex-1 min-w-0">
                      <span className="font-extrabold text-slate-900 text-sm block truncate">
                        {institution}
                      </span>
                      <span className="text-[10px] text-slate-400 font-bold">
                        {order.txRef} {order.purchaseOrderNumber ? `• PO: ${order.purchaseOrderNumber}` : ""}
                      </span>
                    </div>

                    <div className="flex items-center gap-3 flex-shrink-0">
                      <div className={`text-[9px] font-black uppercase px-2 py-0.5 rounded border ${
                        order.paymentStatus === "PAID"
                          ? "bg-emerald-50 text-emerald-700 border-emerald-100"
                          : "bg-amber-50 text-amber-700 border-amber-100"
                      }`}>
                        {order.paymentStatus || "UNPAID"}
                      </div>
                      <span className="text-lg font-black text-slate-900">{total.toLocaleString()} <span className="text-xs text-slate-400">ETB</span></span>
                      <ChevronDown size={16} className={`text-slate-400 transition-transform ${isExpanded ? "rotate-180" : ""}`} />
                    </div>
                  </div>

                  {/* Expanded Actions */}
                  {isExpanded && (
                    <div className="border-t border-slate-100 p-5 bg-slate-50/50 space-y-4">
                      <div className="flex flex-wrap gap-3">
                        {/* Approve */}
                        {order.procurementStatus === "PENDING_APPROVAL" && (
                          <button
                            onClick={() => handleApprove(order.id)}
                            className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-xl text-xs font-black uppercase tracking-wider hover:bg-emerald-700 transition-colors"
                          >
                            <CheckCircle2 size={14} /> Approve Order
                          </button>
                        )}

                        {/* Cancel */}
                        {!["DELIVERED", "CANCELLED"].includes(order.procurementStatus) && (
                          <button
                            onClick={async () => {
                              if (window.confirm("Are you sure you want to cancel this order?")) {
                                try {
                                  await dispatch(updateB2bOrderStatus({ id: order.id, status: "CANCELLED" })).unwrap();
                                  toast.success("Order cancelled");
                                  fetchOrders();
                                } catch (err) { toast.error(err || "Cancel failed"); }
                              }
                            }}
                            className="flex items-center gap-2 px-4 py-2 bg-rose-100 text-rose-700 rounded-xl text-xs font-black uppercase tracking-wider hover:bg-rose-200 transition-colors"
                          >
                            <XCircle size={14} /> Cancel
                          </button>
                        )}

                        {/* Status Update */}
                        {!["DELIVERED", "CANCELLED"].includes(order.procurementStatus) && (
                          <div className="flex items-center gap-2">
                            <select
                              value={statusUpdateId === order.id ? newStatus : ""}
                              onChange={(e) => { setStatusUpdateId(order.id); setNewStatus(e.target.value); }}
                              className="h-9 px-3 bg-white border border-slate-200 rounded-xl text-xs font-bold text-slate-600"
                            >
                              <option value="">Update Status...</option>
                              <option value="PROCESSING">Processing</option>
                              <option value="SHIPPED">Shipped</option>
                              <option value="PARTIALLY_SHIPPED">Partially Shipped</option>
                              <option value="DELIVERED">Delivered</option>
                            </select>
                            {statusUpdateId === order.id && newStatus && (
                              <button
                                onClick={() => handleStatusUpdate(order.id)}
                                className="px-3 py-2 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700"
                              >
                                Apply
                              </button>
                            )}
                          </div>
                        )}
                      </div>

                      {/* Tracking */}
                      <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3 pt-3 border-t border-slate-200">
                        <span className="text-xs font-bold text-slate-500">Tracking #:</span>
                        <span className="text-sm font-extrabold text-slate-800">
                          {order.shipmentTrackingNumber || "Not set"}
                        </span>
                        <div className="flex gap-2 ml-auto">
                          <input
                            placeholder="Enter tracking number"
                            value={expandedId === order.id ? trackingInput : ""}
                            onChange={(e) => setTrackingInput(e.target.value)}
                            className="h-8 px-3 border border-slate-200 rounded-lg text-xs font-medium focus:outline-none w-48"
                          />
                          <button
                            onClick={() => handleSetTracking(order.id)}
                            className="px-3 h-8 bg-slate-800 text-white rounded-lg text-xs font-bold hover:bg-slate-900"
                          >
                            Set
                          </button>
                        </div>
                      </div>

                      {/* View on buyer side */}
                      <Link
                        to={`/b2b/orders/${order.id}`}
                        className="text-xs font-bold text-indigo-600 hover:underline flex items-center gap-1"
                      >
                        <Eye size={12} /> View Full Order Detail
                      </Link>
                    </div>
                  )}
                </div>
              );
            })}

            {/* Pagination */}
            {ordersMeta && ordersMeta.pages > 1 && (
              <div className="flex items-center justify-center gap-2 mt-6">
                {Array.from({ length: ordersMeta.pages }, (_, i) => i + 1).map((p) => (
                  <button
                    key={p}
                    onClick={() => setPage(p)}
                    className={`w-9 h-9 rounded-xl text-xs font-bold transition-colors ${
                      p === page ? "bg-indigo-600 text-white" : "bg-white border border-slate-200 text-slate-600 hover:bg-slate-50"
                    }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            )}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-24 bg-white rounded-3xl border border-slate-100 shadow-sm">
            <AlertTriangle size={48} className="text-slate-200 mb-4" />
            <p className="text-sm font-black text-slate-400 uppercase tracking-widest">No B2B orders found</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminB2bOrders;
